 var ggio_iudft=document.createElement("div");   
ggio_iudft.innerHTML='<style>  .toast-container {  user-select:none;  position: fixed; z-index: 9999; padding: 20px; display: flex; flex-direction: column; gap: 10px; width: 100%; max-width: 450px; pointer-events: none; } [data-position="tr"] { top: 0; right: 0; align-items: flex-end; }  [data-position="tc"] { top: 0; left: 50%; transform: translateX(-50%); align-items: center; }  [data-position="tl"] { top: 0; left: 0; align-items: flex-start; }  [data-position="br"] { bottom: 0; right: 0; align-items: flex-end; flex-direction: column-reverse; }   [data-position="bc"] { bottom: 0; left: 50%; transform: translateX(-50%); align-items: center; flex-direction: column-reverse; }   [data-position="bl"] { bottom: 0; left: 0; align-items: flex-start; flex-direction: column-reverse; }  .toast { user-select:none;     position: relative; overflow: hidden; display: flex; gap: 12px; min-width: 320px;     padding: 16px; border-radius: 12px; box-shadow: 0 10px 15px -3px rgba(0,0,0,0.1);    pointer-events: auto;}  .toast.toast-success {     --toast-accent-color: #16a34a;     background: #ffffff !important;     color: #1e293b !important; }   .toast.toast-error {     --toast-accent-color: #dc2626;     background: #ffffff !important;     color: #1e293b !important; }  .toast.toast-warning {     --toast-accent-color: #f59e0b;     background: #ffffff !important;     color: #1e293b !important; }  .toast.toast-info {     --toast-accent-color: #3b82f6;     background: #ffffff !important;     color: #1e293b !important; }  .toast-icon { display: flex; align-items: center; justify-content: center; flex-shrink: 0; }  .style-accent .toast-icon, .style-bordered .toast-icon, .style-minimal .toast-icon { color: var(--toast-accent-color); }  .toast-close { background: none; border: none; color: inherit; cursor: pointer; font-size: 1.4rem; opacity: 0.4; line-height: 1; padding: 0; margin-left: auto; transition: opacity 0.2s; align-self: flex-start; }   .toast-close:hover { opacity: 1; }  .style-accent { border: 1px solid var(--toast-accent-color); border-left: 6px solid var(--toast-accent-color); }   .style-bordered { border: 2px solid var(--toast-accent-color); }   .toast-progress { position: absolute; bottom: 0; left: 0; height: 5px; width: 100%; background: var(--toast-accent-color); opacity: 0.3; transform-origin: left; z-index: 10; transform: scaleX(1); }   .style-solid .toast-progress { background: rgba(255,255,255,0.7); opacity: 1; }    @keyframes slideInRight { from { transform: translateX(120%); opacity: 0; } to { transform: translateX(0); opacity: 1; } }   @keyframes slideOutRight { to { transform: translateX(120%); opacity: 0; } }   @keyframes slideInLeft { from { transform: translateX(-120%); opacity: 0; } to { transform: translateX(0); opacity: 1; } }   @keyframes slideOutLeft { to { transform: translateX(-120%); opacity: 0; } }   @keyframes slideInDown { from { transform: translateY(-100%); opacity: 0; } to { transform: translateY(0); opacity: 1; } }  @keyframes slideOutUp { to { transform: translateY(-100%); opacity: 0; } }   @keyframes slideInUp { from { transform: translateY(100%); opacity: 0; } to { transform: translateY(0); opacity: 1; } }  @keyframes slideOutDown { to { transform: translateY(100%); opacity: 0; } }  @keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-8px); } 75% { transform: translateX(8px); } }  @keyframes zoomIn { from { transform: scale(0.8); opacity: 0; } to { transform: scale(1); opacity: 1; } }   </style>';
